#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define grep(a,b,c) for(int c=a.head[(b)];c;c=a.nxt[c])
inline int Min(int x,int y){return x<y?x:y;}
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int N=1e6+10,M=2e6+10,K=110,INF=0x3f3f3f3f;
struct Graph
{
	int head[N],des[M],val[M],nxt[M],cap[M],cnt;
	inline void ins(int x,int y,int z){des[++cnt]=y;nxt[cnt]=head[x];head[x]=cnt;cap[cnt]=z;}
	inline void add(int x,int y,int z){ins(x,y,z);ins(y,x,0);}
	inline void Init(){memset(head,0,sizeof(head));cnt=1;}
}a;
bool A[K][K];int dep[N],que[N],H,T,s,t;
inline bool bfs()
{
	memset(dep,0,sizeof(dep));dep[que[H=T=1]=s]=1;
	while(H<=T)
	{
		int u=que[H++];grep(a,u,i)
		{
			int v=a.des[i];if(dep[v]||!a.cap[i])continue;
			dep[que[++T]=v]=dep[u]+1;
		}
	} return dep[t];
}
inline int dfs(int u,int in)
{
	if(u==t)return in;int out=0;
	grep(a,u,i)
	{
		int v=a.des[i];if(dep[v]^(dep[u]+1)||!a.cap[i])continue;
		int tmp=dfs(v,Min(a.cap[i],in));
		a.cap[i]-=tmp;a.cap[i^1]+=tmp;out+=tmp;if(!(in-=tmp))break;
	}
	out?0:dep[u]=0;return out;
}
inline int dinic(int u,int v){s=u;t=v;int res=0;while(bfs())res+=dfs(s,INF);return res;}
int main()
{
	int n=read(),p=read(),q=read();a.Init();
	rep(1,n,i)rep(1,p,j)if(read())a.add(j,i+p,1);
	rep(1,n,i)a.add(p+i,p+i+n,1);
	rep(1,n,i)rep(1,q,j)if(read())a.add(i+p+n,j+p+2*n,1);
	rep(1,p,i)a.add(2*n+p+q+1,i,1);rep(1,q,i)a.add(i+p+2*n,2*n+p+q+2,1);
	printf("%d\n",dinic(2*n+p+q+1,2*n+p+q+2));
}
